SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_security_permit_head ON sc_security_permit_head CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_security_permit_head() RETURNS trigger AS $BODY$
BEGIN

  -- Default
  if coalesce(NEW.request_client::text, '') = '' or NEW.request_client = ' ' then
    NEW.request_client := trim(both pka_com_login.login_pc);
  end if;
  if coalesce(NEW.request_date::text, '') = '' then
    NEW.request_date := statement_timestamp();
  end if;
  if coalesce(NEW.request_branch::text, '') = '' or NEW.request_branch = ' ' then
    NEW.request_branch := trim(both current_setting('app.login_br', true));
  end if;

  -- W = รอการอนุมัติ , Y = อนุมัติ, N = ไม่อนุมัติ , C = ผู้ร้องขอ ยกเลิกเอง , E = มีรายการ Error ,T = Terminate
  if coalesce(NEW.permit_result::text, '') = '' or NEW.permit_result = ' ' then
    NEW.permit_result := 'W';
  end if;

  if OLD.permit_result = 'W' and NEW.permit_result != 'W' then
    -- อนุมัติสถานะ permit_result
      NEW.permit_id := pka_com_function.fp_login_id;
      NEW.permit_client := pka_com_function.fp_login_pc;
      NEW.permit_date := statement_timestamp();
      NEW.permit_branch  := pka_com_function.fp_login_br;
  end if;

  -- Auto
  if pka.auto_seqno then
    if coalesce(NEW.request_group::text, '') = '' or NEW.request_group = 0 then
      select max(request_group) into STRICT NEW.request_group
      from  sc_security_permit_head
      where (request_id = NEW.request_id);
      NEW.request_group := coalesce(NEW.request_group,0) + 1;
    end if;
  end if;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_security_permit_head() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_security_permit_head
	BEFORE INSERT OR UPDATE ON sc_security_permit_head FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_security_permit_head();

